public int smallestFactorization(int num) {
    if (num == 1) return 1;
    long result = 0, factor = 1;
    for (int i = 9; i > 1; --i) {
        while (num % i == 0) {
            num /= i;
            result += i * factor;
            factor *= 10;
            if (result > Integer.MAX_VALUE) return 0;
        }
    }
    return num == 1 ? (int) result : 0;
}
